example.code:
age = 20

# Condition simple
if age >= 18:
    print("Majeur")

# Avec else
if age >= 18:
    print("Majeur")
else:
    print("Mineur")

# Avec elif
if age < 13:
    print("Enfant")
elif age < 18:
    print("Adolescent")
else:
    print("Adulte")

# Opérateurs logiques
temperature = 22
soleil = True

if temperature > 20 and soleil:
    print("Parfait pour sortir !")

if temperature < 0 or temperature > 40:
    print("Température extrême")

# Syntaxe ternaire (one-liner)
statut = "majeur" if age >= 18 else "mineur"
print(statut)  # majeur
